import { useState } from "react";
import { motion } from "framer-motion";
import { RefreshCw, Copy, ChevronDown, ChevronUp } from "lucide-react";
import SEOHead from "@/components/SEOHead";
import AdPlaceholder from "@/components/AdPlaceholder";
import RelatedTools from "@/components/RelatedTools";
import ShareButton from "@/components/ShareButton";
import SliderInput from "@/components/SliderInput";
import FAQItem from "@/components/FAQItem";


const FAQS = [
  { q: "Is this random number generator truly random?", a: "This generator uses the Web Crypto API (crypto.getRandomValues()), which produces cryptographically secure pseudo-random numbers seeded from the operating system's entropy pool - the same source used in TLS/HTTPS encryption. This is considered cryptographically secure and suitable for security, games, simulations, and any application where predictability would be a problem." },
  { q: "What is the difference between random and pseudo-random?", a: "True random numbers come from unpredictable physical processes (radioactive decay, thermal noise). Pseudo-random numbers use deterministic algorithms that produce statistically random-appearing sequences from a seed. Cryptographically secure pseudo-random generators (like the Web Crypto API used here) are seeded from true entropy sources, making them functionally indistinguishable from true random for all practical purposes." },
  { q: "Can I use this to pick lottery numbers?", a: "Yes - use list mode, set the minimum to 1, maximum to your lottery's highest number (e.g., 49 for 6/49), set quantity to 6, and enable 'unique numbers'. This generates 6 non-repeating numbers. Each number has an equal probability of selection. Historically, lottery numbers generated by hardware random number generators have the same expected return as any other selection method." },
  { q: "What is the range limit for this generator?", a: "This generator works with any integer range. The default is 1-100. You can set any minimum and maximum integer values up to JavaScript's safe integer limit (~9 quadrillion). For very large ranges with unique mode, generation may take slightly longer due to the shuffling algorithm, but the results remain cryptographically secure." },
  { q: "How do I generate a random number between two specific numbers?", a: "Set the minimum to your lower bound and maximum to your upper bound. Both endpoints are inclusive - a range of 1 to 6 includes both 1 and 6, simulating a fair die roll. For a decimal range, use large integer ranges and divide the result (e.g., 1-1000 for 0.001-1.000 resolution)." },
  { q: "What is the probability of getting any specific number?", a: "Each number in the range has an equal probability of 1/(max - min + 1). For a range of 1-100, each number has a 1% chance. For 1-6 (die roll), each number has 1/6 - 16.67% chance. This uniform distribution is maintained by the modulo operation applied to the cryptographically random 32-bit integer from the Web Crypto API." },
  { q: "How does unique number generation work?", a: "In unique mode, the generator creates a complete pool of all numbers in the range, uses the Fisher-Yates shuffle algorithm with cryptographically random indices, and selects the first N numbers. This guarantees each selected number appears exactly once and preserves the uniform distribution. This is equivalent to drawing numbers without replacement from a hat." },
  { q: "Can I use this for a raffle or giveaway?", a: "Yes - set the range to 1 through your number of participants, generate one number, and the winner is whoever holds that number. For maximum fairness, use unique mode to generate multiple winners without repeats. The cryptographically secure generation ensures results are unbiased and unmanipulable." },
];

const USE_CASES = [
  ["Lottery numbers (6/49)", "Min: 1, Max: 49, Qty: 6", "Unique mode on"],
  ["Standard die roll", "Min: 1, Max: 6, Qty: 1", "Single number"],
  ["Two dice", "Min: 1, Max: 6, Qty: 2", "Allow repeats"],
  ["Raffle winner (100 entries)", "Min: 1, Max: 100, Qty: 1", "Single number"],
  ["Top 3 winners (raffle)", "Min: 1, Max: 100, Qty: 3", "Unique mode on"],
  ["Coin flip (heads/tails)", "Min: 1, Max: 2", "1=heads, 2=tails"],
  ["Random month (1-12)", "Min: 1, Max: 12, Qty: 1", "Single number"],
  ["Card draw (52-card deck)", "Min: 1, Max: 52, Qty: 5", "Unique mode on"],
];

function cryptoRandInt(min: number, max: number): number {
  const range = max - min + 1;
  const arr = new Uint32Array(1);
  crypto.getRandomValues(arr);
  return min + (arr[0] % range);
}

export default function RandomNumberGenerator() {
  const [min, setMin] = useState(1);
  const [max, setMax] = useState(100);
  const [quantity, setQuantity] = useState(1);
  const [unique, setUnique] = useState(false);
  const [numbers, setNumbers] = useState<number[]>([cryptoRandInt(1, 100)]);
  const [copied, setCopied] = useState(false);
  const [error, setError] = useState("");

  const generate = () => {
    const safeMin = Math.min(min, max);
    const safeMax = Math.max(min, max);
    if (unique && quantity > safeMax - safeMin + 1) {
      setError("Range too small for unique numbers. Increase the range or lower the quantity.");
      return;
    }
    setError("");
    if (quantity === 1) { setNumbers([cryptoRandInt(safeMin, safeMax)]); return; }
    const result: number[] = [];
    const pool = unique ? Array.from({ length: safeMax - safeMin + 1 }, (_, i) => safeMin + i) : null;
    const tempPool = pool ? [...pool] : null;
    for (let i = 0; i < quantity; i++) {
      if (unique && tempPool) {
        const idx = cryptoRandInt(0, tempPool.length - 1);
        result.push(tempPool.splice(idx, 1)[0]);
      } else { result.push(cryptoRandInt(safeMin, safeMax)); }
    }
    setNumbers(result);
  };

  const copy = () => { navigator.clipboard.writeText(numbers.join(", ")); setCopied(true); setTimeout(() => setCopied(false), 2000); };

  return (
    <>
      <SEOHead
        title="Free Random Number Generator Online - Generate Secure Random Numbers Instantly | CalcHive"
        description="Free online random number generator. Generate cryptographically secure random numbers within any range with unique results instantly. 100% free, no signup required."
        canonical="/random-number-generator"
        keywords="free random number generator, random number generator online free, generate random numbers free, secure random number generator free, free number picker online"
        category="Math Calculators"
        faqs={FAQS}
      />
      <main className="max-w-3xl mx-auto px-4 sm:px-6 py-10">
        <div className="mb-8">
          <span className="text-xs font-semibold uppercase tracking-widest text-amber-600 dark:text-amber-400 bg-amber-50 dark:bg-amber-950/50 px-3 py-1 rounded-full mb-4 inline-block">Math</span>
          <h1 className="text-3xl sm:text-4xl font-extrabold text-foreground tracking-tight mb-3">Free Random Number Generator Online</h1>
          <p className="text-muted-foreground leading-relaxed">Use this free random number generator to generate random numbers free within any range. This random number generator online free includes secure random number generator free behavior and works as a free number picker online for games, contests, and more.</p>
        </div>
        <AdPlaceholder size="banner" className="mb-8" />
        <section className="bg-card border border-border rounded-2xl p-6 sm:p-8 shadow-md mb-8">
          <div className="space-y-6 mb-6">
            <SliderInput id="rng-min" label="Minimum" value={min} min={-1000000} max={max - 1} step={1} onChange={setMin} testId="input-min" />
            <SliderInput id="rng-max" label="Maximum" value={max} min={min + 1} max={1000000} step={1} onChange={setMax} testId="input-max" />
            <SliderInput id="rng-qty" label="Quantity" value={quantity} min={1} max={100} step={1} onChange={setQuantity} testId="input-quantity" helpText="numbers to generate" />
          </div>
          {error && (
            <p className="mb-4 rounded-xl border border-red-200 bg-red-50 px-3 py-2 text-sm font-medium text-red-700 dark:border-red-900/60 dark:bg-red-950/30 dark:text-red-300" role="alert">
              {error}
            </p>
          )}
          <label className="flex items-center gap-3 mb-6 cursor-pointer">
            <input type="checkbox" checked={unique} onChange={e => setUnique(e.target.checked)} className="accent-primary w-4 h-4" />
            <span className="text-sm font-medium text-foreground">Generate unique numbers (no repeats)</span>
          </label>
          <button onClick={generate} className="w-full flex items-center justify-center gap-2 bg-primary text-primary-foreground font-bold py-3 rounded-xl hover:opacity-90 transition-opacity shadow-md mb-6">
            <RefreshCw className="w-4 h-4" /> Generate
          </button>
          <motion.div key={numbers.join(",")} initial={{ opacity: 0.7, y: 4 }} animate={{ opacity: 1, y: 0 }} transition={{ duration: 0.25 }}>
            <div className="bg-gradient-to-br from-amber-500 to-amber-700 rounded-2xl p-6 text-center shadow-lg">
              <p className="text-xs font-semibold uppercase tracking-widest text-white/70 mb-3">Result{numbers.length > 1 ? "s" : ""}</p>
              {numbers.length === 1 ? (
                <p className="text-7xl font-black text-white tracking-tight" data-testid="result">{numbers[0]}</p>
              ) : (
                <div className="flex flex-wrap justify-center gap-2">
                  {numbers.map((n, i) => (
                    <span key={i} className="text-2xl font-black text-white bg-white/20 px-3 py-1 rounded-lg">{n}</span>
                  ))}
                </div>
              )}
              <button onClick={copy} className="mt-4 flex items-center gap-1.5 mx-auto text-xs text-white/70 hover:text-white transition-colors">
                <Copy className="w-3 h-3" /> {copied ? "Copied!" : "Copy"}
              </button>
            </div>
            <p className="text-xs text-muted-foreground mt-3 text-center">Range {min}-{max} - {max - min + 1} possible values - Generated via Web Crypto API</p>
          </motion.div>
        </section>
        <ShareButton />

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">How to Generate Random Numbers for Free</h2>
          <p className="text-muted-foreground leading-relaxed">This generator uses the Web Cryptography API's crypto.getRandomValues() which fills an array with cryptographically secure random 32-bit integers. To get a number in a specific range, the 32-bit value is mapped using modulo arithmetic. For unique mode, a Fisher-Yates shuffle selects non-repeating values from the full range pool.</p>
          <div className="bg-accent/60 border border-border rounded-2xl p-5 font-mono text-sm text-foreground space-y-1">
            <p>Random integer = crypto.getRandomValues(Uint32Array)</p>
            <p>In-range value = min + (random_value mod (max - min + 1))</p>
            <p className="text-xs text-muted-foreground mt-2">Probability per value = 1 / (max - min + 1)</p>
            <p className="text-xs text-muted-foreground">Unique mode uses Fisher-Yates shuffle for unbiased selection</p>
          </div>

          <h2 className="text-2xl font-bold text-foreground">What Makes a Cryptographically Secure Random Number</h2>
          <div className="overflow-x-auto">
            <table className="w-full text-sm border border-border rounded-xl overflow-hidden">
              <thead className="bg-muted/60">
                <tr>
                  {["Use Case", "Settings", "Notes"].map(h => <th key={h} className="text-left py-3 px-4 font-semibold text-foreground">{h}</th>)}
                </tr>
              </thead>
              <tbody className="divide-y divide-border">
                {USE_CASES.map(([use, settings, notes]) => (
                  <tr key={use} className="hover:bg-muted/30">
                    <td className="py-2.5 px-4 font-semibold text-foreground">{use}</td>
                    <td className="py-2.5 px-4 font-mono text-xs text-amber-600 dark:text-amber-400">{settings}</td>
                    <td className="py-2.5 px-4 text-muted-foreground">{notes}</td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </section>

        <section className="mb-8 space-y-6">
          <h2 className="text-2xl font-bold text-foreground">Free Number Randomizer for Games Contests and More</h2>
          <p className="text-muted-foreground leading-relaxed">Use this free tool on any device to solve the calculation instantly, check your work, and get a clear result without downloads or signup.</p>
        </section>

        <section className="mb-8">
          <h3 className="text-xl font-bold text-foreground mb-4">Frequently Asked Questions</h3>
          <div className="space-y-3">{FAQS.map(f => <FAQItem key={f.q} q={f.q} a={f.a} />)}</div>
        </section>
        <AdPlaceholder size="rectangle" className="mx-auto mb-8" />
        <RelatedTools exclude="/random-number-generator" headingLevel="h3" />
      </main>
    </>
  );
}


